import React from 'react';
import { useForm } from './useForm';
import './styles.css';

interface FormValues {
  name: string;
  email: string;
}

const validate = (values: FormValues) => {
  const errors: Partial<Record<keyof FormValues, string>> = {};
  if (!values.name.trim()) errors.name = 'Name is required';
  if (!values.email.trim()) errors.email = 'Email is required';
  else if (!/^[^@]+@[^@]+\.[^@]+$/.test(values.email)) errors.email = 'Invalid email';
  return errors;
};

export default function App() {
  const {
    values, errors, touched, dirty, isValid,
    getFieldProps, handleSubmit, resetForm,
  } = useForm<FormValues>({
    initialValues: { name: '', email: '' },
    validate,
  });

  const onSubmit = (vals: FormValues) => {
    alert(`Submitted: ${JSON.stringify(vals)}`);
  };

  return (
    <div style={{ padding: '2rem', fontFamily: 'system-ui, sans-serif' }}>
      <h1 style={{ marginBottom: '1rem' }}>useForm</h1>
      <form onSubmit={handleSubmit(onSubmit)} className="form">
        <div className="form__field">
          <label htmlFor="name">Name</label>
          <input id="name" data-testid="field-name" {...getFieldProps('name')} />
          {touched.name && errors.name && (
            <span data-testid="error-name" className="form__error">{errors.name}</span>
          )}
        </div>
        <div className="form__field">
          <label htmlFor="email">Email</label>
          <input id="email" data-testid="field-email" {...getFieldProps('email')} />
          {touched.email && errors.email && (
            <span data-testid="error-email" className="form__error">{errors.email}</span>
          )}
        </div>
        <div className="form__meta">
          <span data-testid="dirty">Dirty: {dirty ? 'Yes' : 'No'}</span>
          <span data-testid="valid">Valid: {isValid ? 'Yes' : 'No'}</span>
        </div>
        <div className="form__actions">
          <button data-testid="submit" type="submit">Submit</button>
          <button data-testid="reset" type="button" onClick={resetForm}>Reset</button>
        </div>
      </form>
    </div>
  );
}

import { useState, useCallback, useMemo } from 'react';

interface UseFormConfig<T extends Record<string, any>> {
  initialValues: T;
  validate: (values: T) => Partial<Record<keyof T, string>>;
}

interface FieldProps {
  value: any;
  onChange: (e: React.ChangeEvent<HTMLInputElement>) => void;
  onBlur: () => void;
  name: string;
}

interface UseFormReturn<T extends Record<string, any>> {
  values: T;
  errors: Partial<Record<keyof T, string>>;
  touched: Partial<Record<keyof T, boolean>>;
  dirty: boolean;
  isValid: boolean;
  getFieldProps: (name: keyof T) => FieldProps;
  handleSubmit: (onSubmit: (values: T) => void) => (e: React.FormEvent) => void;
  resetForm: () => void;
  setFieldValue: (name: keyof T, value: any) => void;
}

/**
 * Custom hook for form state management with validation.
 *
 * @param config - Form configuration including initialValues and validate function
 * @returns Form helpers: values, errors, touched, dirty, isValid, getFieldProps, handleSubmit, resetForm, setFieldValue
 */
export function useForm<T extends Record<string, any>>(
  config: UseFormConfig<T>
): UseFormReturn<T> {
  // TODO: Track values, touched, errors in state
  // TODO: Run validate on every values change
  // TODO: Implement getFieldProps to return { value, onChange, onBlur, name }
  // TODO: Implement handleSubmit to validate, prevent default, call onSubmit if valid
  // TODO: Implement resetForm and setFieldValue
  // TODO: Derive dirty (values !== initialValues) and isValid (no errors)

  return {
    values: config.initialValues,
    errors: {},
    touched: {},
    dirty: false,
    isValid: false,
    getFieldProps: (name) => ({ value: '', onChange: () => {}, onBlur: () => {}, name: String(name) }),
    handleSubmit: () => (e) => { e.preventDefault(); },
    resetForm: () => {},
    setFieldValue: () => {},
  };
}

.form {
  max-width: 24rem;
}

.form__field {
  margin-bottom: 1rem;
}

.form__field label {
  display: block;
  font-size: 0.8125rem;
  font-weight: 500;
  color: #374151;
  margin-bottom: 0.25rem;
}

.form__field input {
  width: 100%;
  padding: 0.5rem 0.75rem;
  border: 1px solid #d1d5db;
  border-radius: 0.375rem;
  font-size: 0.875rem;
  outline: none;
  transition: border-color 0.15s ease;
  box-sizing: border-box;
}

