  border-color: #3b82f6;
  box-shadow: 0 0 0 3px rgba(59,130,246,0.15);
}

.form__error {
  display: block;
  font-size: 0.75rem;
  color: #ef4444;
  margin-top: 0.25rem;
}

.form__meta {
  display: flex;
  gap: 1rem;
  font-size: 0.8125rem;
  color: #6b7280;
  margin-bottom: 1rem;
}

.form__actions {
  display: flex;
  gap: 0.5rem;
}

.form__actions button {
  padding: 0.5rem 1rem;
  border: 1px solid #d1d5db;
  border-radius: 0.375rem;
  background: #f9fafb;
  cursor: pointer;
  font-size: 0.875rem;
}

.form__actions button[type='submit'] {
  background: #3b82f6;
  color: white;
  border-color: #3b82f6;
}

.form__actions button:hover {
  opacity: 0.9;
}

