import { render, screen, fireEvent } from '@testing-library/react';
import '@testing-library/jest-dom';
import React from 'react';
import { useForm } from './useForm';

interface TestValues {
  name: string;
  email: string;
}

const validate = (values: TestValues) => {
  const errors: Partial<Record<keyof TestValues, string>> = {};
  if (!values.name.trim()) errors.name = 'Name is required';
  if (!values.email.trim()) errors.email = 'Email is required';
  else if (!/^[^@]+@[^@]+\.[^@]+$/.test(values.email)) errors.email = 'Invalid email';
  return errors;
};

function Harness({ onSubmit }: { onSubmit?: (v: TestValues) => void }) {
  const { values, errors, touched, dirty, isValid, getFieldProps, handleSubmit, resetForm } = useForm<TestValues>({
    initialValues: { name: '', email: '' },
    validate,
  });
  return (
    <form onSubmit={handleSubmit(onSubmit || (() => {}))}>
      <input data-testid="field-name" {...getFieldProps('name')} />
      {touched.name && errors.name && <span data-testid="error-name">{errors.name}</span>}
      <input data-testid="field-email" {...getFieldProps('email')} />
      {touched.email && errors.email && <span data-testid="error-email">{errors.email}</span>}
      <span data-testid="dirty">{dirty ? 'dirty' : 'clean'}</span>
      <span data-testid="valid">{isValid ? 'valid' : 'invalid'}</span>
      <button data-testid="submit" type="submit">Submit</button>
      <button data-testid="reset" type="button" onClick={resetForm}>Reset</button>
    </form>
  );
}

describe('useForm', () => {
  it('initializes with initial values', () => {
    render(<Harness />);
    expect(screen.getByTestId('field-name')).toHaveValue('');
    expect(screen.getByTestId('field-email')).toHaveValue('');
  });

  it('updates values on change', () => {
    render(<Harness />);
    fireEvent.change(screen.getByTestId('field-name'), { target: { value: 'Alice' } });
    expect(screen.getByTestId('field-name')).toHaveValue('Alice');
  });

  it('marks field as dirty when changed', () => {
    render(<Harness />);
    expect(screen.getByTestId('dirty')).toHaveTextContent('clean');
    fireEvent.change(screen.getByTestId('field-name'), { target: { value: 'A' } });
    expect(screen.getByTestId('dirty')).toHaveTextContent('dirty');
  });

  it('shows error only after field is touched (blurred)', () => {
    render(<Harness />);
    expect(screen.queryByTestId('error-name')).not.toBeInTheDocument();
    fireEvent.blur(screen.getByTestId('field-name'));
    expect(screen.getByTestId('error-name')).toHaveTextContent('Name is required');
  });

  it('clears error when field becomes valid', () => {
    render(<Harness />);
    fireEvent.blur(screen.getByTestId('field-name'));
    expect(screen.getByTestId('error-name')).toBeInTheDocument();
    fireEvent.change(screen.getByTestId('field-name'), { target: { value: 'Alice' } });
    expect(screen.queryByTestId('error-name')).not.toBeInTheDocument();
  });

  it('isValid reflects validation state', () => {
    render(<Harness />);
    expect(screen.getByTestId('valid')).toHaveTextContent('invalid');
    fireEvent.change(screen.getByTestId('field-name'), { target: { value: 'Alice' } });
    fireEvent.change(screen.getByTestId('field-email'), { target: { value: 'alice@test.com' } });
    expect(screen.getByTestId('valid')).toHaveTextContent('valid');
  });

  it('handleSubmit prevents default and calls onSubmit when valid', () => {
    const spy = jest.fn();
    render(<Harness onSubmit={spy} />);
    fireEvent.change(screen.getByTestId('field-name'), { target: { value: 'Alice' } });
    fireEvent.change(screen.getByTestId('field-email'), { target: { value: 'a@b.com' } });
    fireEvent.click(screen.getByTestId('submit'));
    expect(spy).toHaveBeenCalledWith({ name: 'Alice', email: 'a@b.com' });
  });

  it('handleSubmit does not call onSubmit when invalid', () => {
    const spy = jest.fn();
    render(<Harness onSubmit={spy} />);
    fireEvent.click(screen.getByTestId('submit'));
    expect(spy).not.toHaveBeenCalled();
  });

  it('resetForm restores initial values and clears touched', () => {
    render(<Harness />);
    fireEvent.change(screen.getByTestId('field-name'), { target: { value: 'Alice' } });
    fireEvent.blur(screen.getByTestId('field-name'));
    fireEvent.click(screen.getByTestId('reset'));
    expect(screen.getByTestId('field-name')).toHaveValue('');
    expect(screen.getByTestId('dirty')).toHaveTextContent('clean');
    expect(screen.queryByTestId('error-name')).not.toBeInTheDocument();
  });
});

